#include<bits/stdc++.h>
using namespace std;
int a[1000010];
long long sum[1000010],ans[1000010];
vector<int> v;
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        sum[i]=sum[i-1]+a[i];
    }
    int k;
    scanf("%d",&k);
    if(n==1)
    {
        printf("%d\n",k-a[1]+1);
        for(int i=a[1];i<=k;i++)
        {
            printf("%d ",i);
        }
        return 0;
    }
    for(int i=1;i<=n;i++)
    {
        int j=lower_bound(sum+i+1,sum+1+n,sum[i]*2)-sum;
        if(sum[j]<sum[i]*2)
        {
            if(sum[i]>k)
            {
                continue;
            }
            ans[sum[i]]++;
            ans[k+1]--;
            continue;
        }
        // printf("%d %d %lld %lld\n",i,j,sum[i],sum[j]-sum[i]);
        if(sum[i]>k)
        {

        }
        else if(sum[j]-sum[i]>k)
        {
            ans[sum[i]]++;
            ans[k+1]--;
        }
        else
        {
            ans[sum[i]]++;
            ans[sum[j]-sum[i]]--;
        }

    }
    long long res=0;
    for(int i=1;i<=k;i++)
    {
        res+=ans[i];
        if(res!=0)
        {
            v.push_back(i);
        }
    }
    printf("%d\n",v.size());
    for(int i:v)
    {
        printf("%d ",i);
    }
    return 0;
}
